class UnionFind {
    std::vector<long> par;

    std::size_t _root(std::size_t v) {
        if (par[v] < 0) {
            return v;
        } else {
            return par[v] = _root(par[v]);
        }
    }

public:
    UnionFind(std::size_t n) : par(n, -1) {}

    std::size_t root(std::size_t v) {
        assert(v < par.size());
        return _root(v);
    }

    std::size_t size(std::size_t v) {
        assert(v < par.size());
        return -par[_root(v)];
    }

    bool unite(std::size_t u, std::size_t v) {
        assert(u < par.size() && v < par.size());
        u = _root(u);
        v = _root(v);
        if (u == v) {
            return false;
        }
        if (par[u] < par[v]) {
            std::swap(u, v);
        }
        par[v] += par[u];
        par[u] = v;
        return true;
    }

    bool same(std::size_t u, std::size_t v) {
        assert(u < par.size() && v < par.size());
        return _root(u) == _root(v);
    }
};

constexpr array<i32, 4> dx = {-1, 0, 1, 0}, dy = {0, 1, 0, -1};

constexpr i32 BSIZE = 9;

struct Act {
    i32 type, x, y;
    Act(i32 _t, i32 _x, i32 _y) : type(_t), x(_x), y(_y) {}
};

class Game {
    static constexpr i32 MAX_WALL = 10;

    array<array<bool, BSIZE>, BSIZE> apple;
    array<array<array<bool, BSIZE>, BSIZE>, 4> can_move;
    array<pair<i32, i32>, 2> poses;
    array<i32, 2> wall_cnt;
    array<i32, 2> score;
    i32 turn;

    bool is_connected() {
        UnionFind uf(BSIZE * BSIZE);
        REP(d, 4) REP(i, BSIZE) REP(j, BSIZE) {
            if (can_move[d][i][j]) {
                uf.unite(i * BSIZE + j, (i + dx[d]) * BSIZE + j + dy[d]);
            }
        }
        return uf.size(0) == BSIZE * BSIZE;
    }

public:
    bool is_ok(Act act) {
        auto [x, y] = poses[turn];
        if (act.type == 0) {
            return can_move[act.x][x][y];
        } else if (act.type == 1) {
            if (act.x < 0 || act.x > BSIZE - 2 || act.y < 0 || act.y > BSIZE - 2) {
                return false;
            }
            if (wall_cnt[turn] == MAX_WALL) {
                return false;
            }
            if (!can_move[2][x][y] || !can_move[2][x][y + 1]) {
                return false;
            }
            can_move[2][x][y] = can_move[2][x][y + 1] = can_move[0][x + 1][y] = can_move[0][x + 1][y + 1] = true;
            bool res = is_connected();
            can_move[2][x][y] = can_move[2][x][y + 1] = can_move[0][x + 1][y] = can_move[0][x + 1][y + 1] = false;
            return res;
        } else if (act.type == 2) {
            if (act.x < 0 || act.x > BSIZE - 2 || act.y < 0 || act.y > BSIZE - 2) {
                return false;
            }
            if (wall_cnt[turn] == MAX_WALL) {
                return false;
            }
            if (!can_move[1][x][y] || !can_move[1][x + 1][y]) {
                return false;
            }
            can_move[1][x][y] = can_move[1][x + 1][y] = can_move[3][x][y + 1] = can_move[3][x + 1][y + 1] = true;
            bool res = is_connected();
            can_move[1][x][y] = can_move[1][x + 1][y] = can_move[3][x][y + 1] = can_move[3][x + 1][y + 1] = false;
            return res;
        } else {
            return false;
        }
    }

    vector<Act> candidate_acts() {
        vector<Act> res;
        REP(d, 4) {
            if (is_ok(Act(0, d, 0))) {
                res.emplace_back(0, d, 0);
            }
        }
        REP(i, BSIZE - 1) REP(j, BSIZE - 1) {
            if (is_ok(Act(1, i, j))) {
                res.emplace_back(1, i, j);
            }
            if (is_ok(Act(1, i, j))) {
                res.emplace_back(1, i, j);
            }
        }
        return res;
    }

    bool apply_act(Act act, bool check = true) {
        if (check && !is_ok(act)) {
            return false;
        }
        if (act.type == 0) {  // 隣接マスへ移動
            poses[turn].first += dx[act.x];
            poses[turn].second += dy[act.x];
            if (apple[poses[turn].first][poses[turn].second]) {
                score[turn] += 1;
                apple[poses[turn].first][poses[turn].second];
            }
        } else if (act.type == 1) {
            i32 x = act.x, y = act.y;
            can_move[2][x][y] = can_move[2][x][y + 1] = can_move[0][x + 1][y] = can_move[0][x + 1][y + 1] = true;
            wall_cnt[turn] += 1;
        } else {
            i32 x = act.x, y = act.y;
            can_move[1][x][y] = can_move[1][x + 1][y] = can_move[3][x][y + 1] = can_move[3][x + 1][y + 1] = true;
            wall_cnt[turn] += 1;
        }

        turn ^= 1;
        return true;
    }

    void print_board() {
        cerr << "Score: " << score[0] << ' ' << score[1] << '\n'
             << "Wall counter: " << wall_cnt[0] << " " << wall_cnt[1] << '\n'
             << endl;
        REP(i, BSIZE) {
            REP(j, BSIZE) {
                bool is_f = i == poses[0].first && j == poses[0].second;
                bool is_s = i == poses[1].first && j == poses[1].second;
                if (is_f && is_s)
                    cerr << " AB";
                else if (is_f)
                    cerr << " A ";
                else if (is_s)
                    cerr << " B ";
                else {
                    if (apple[i][j])
                        cerr << " # ";
                    else
                        cerr << " . ";
                }
                if (j < BSIZE - 1) cerr << (can_move[1][i][j] ? " . " : " | ");
            }
            cerr << endl;
            if (i < BSIZE - 1) {
                REP(j, BSIZE) {
                    if (j) cerr << "   ";
                    cerr << (!can_move[2][i][j] ? "---" : "   ");
                }
            }
            cerr << endl;
        }
        cerr << endl;
    }

    Game(array<array<bool, BSIZE>, BSIZE> a) : apple(move(a)), can_move(), poses(), wall_cnt(), score() {
        REP(d, 4) REP(x, BSIZE) REP(y, BSIZE) {
            i32 tx = x + dx[d];
            i32 ty = y + dy[d];
            can_move[d][x][y] = tx >= 0 && tx < BSIZE && ty >= 0 && ty < BSIZE;
        }
        poses[0] = {8, 4}, poses[1] = {0, 4};
        wall_cnt[0] = wall_cnt[1] = 0;
        score[0] = score[1] = 0;
    }

    i32 cur_turn() const {
        return turn;
    }

    i32 eval(i32 turn) const {
        return score[turn] - score[turn ^ 1];
    }
};

Act choose(Game &game) {
    i32 turn = game.cur_turn();
    Vec<Act> acts = game.candidate_acts();
    i32 mx = -1001001001;
    Act best_act(-1, -1, -1);
    for (Act act : acts) {
        Game g = game;
        g.apply_act(act);
        i32 ev = g.eval(turn);
        if (ev > mx) {
            mx = ev;
            best_act = act;
        }
    }
    return best_act;
}

int main() {
    string name;
    cin >> name;
    array<array<bool, BSIZE>, BSIZE> board;
    REP(i, BSIZE) REP(j, BSIZE) {
        char c;
        cin >> c;
        board[i][j] = c == '#';
    }
    Game game(move(board));

    int turn = 0, myturn = (name == "First" ? 0 : 1);
    while (true) {
        if (turn == myturn) {
            Act act = choose(game);
            game.apply_act(act);
            if (act.type == 0) {
                cout << act.type << ' ' << act.x << '\n';
            } else {
                cout << act.type << ' ' << act.x << ' ' << act.y << '\n';
            }
        } else {
            i32 ty;
            cin >> ty;
            if (ty == 0) {
                i32 d;
                cin >> d;
                game.apply_act(Act(ty, d, 0));
            } else if (ty <= 2) {
                i32 x, y;
                cin >> x >> y;
                game.apply_act(Act(ty, x, y));
            } else {
                break;
            }
        }
        turn ^= 1;
    }
}
